  ('islands-e7b0146b-moex-00026', 'islands-e7b0146b', 'islands-e7b0146b-moex-114-9f7bb576', 'sub-islands-e7b0146b-01', NULL, 'single_choice', '臺北市議會依據建築法第101條規定授權，制定臺北市建築管理規範。依我國地方制度法，關於 此一規定，下列敘述何者正確？', '["屬於自治規則，其效力相當於法規命令", "屬於自律規則，其效力相當於中央法律", "屬於自治條例，如與法律相牴觸則無效", "屬於行政規則，內容不可影響人民的權利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "44394191c8ff", "answer_pdf_sha1": "345fcb11fcba", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗（作文、英文閱讀與法學知識）", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "文化行政"}'::jsonb, NULL),
