  ('islands-e7b0146b-moex-00028', 'islands-e7b0146b', 'islands-e7b0146b-moex-114-9f7bb576', 'sub-islands-e7b0146b-01', NULL, 'single_choice', '下列對於我國憲法制定與發展歷史的敘述，何者正確？', '["中華民國憲法制定於民國25年，並在民國26年1月1日公布實施", "中華民國憲法的內容主要繼受自日本與德國的憲法，並經立法院同意通過", "民國111年修憲通過降低選舉權之年齡到18歲", "中華民國憲法修改的過程中，廢除國民大會，將修憲的權限交給立法院，並須經公民複決"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "44394191c8ff", "answer_pdf_sha1": "345fcb11fcba", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗（作文、英文閱讀與法學知識）", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "文化行政"}'::jsonb, NULL),
  ('islands-e7b0146b-moex-00029', 'islands-e7b0146b', 'islands-e7b0146b-moex-114-9f7bb576', 'sub-islands-e7b0146b-01', NULL, 'single_choice', '依據司法院釋字第342號解釋意旨，下列敘述何者正確？', '["為維護民主憲政秩序，僅需法律案之立法程序存有瑕疵，則釋憲機關即得宣告該法律案牴觸憲 法而屬無效", "為尊重立法機關之民主正當性，縱使法律案之立法程序存有瑕疵，釋憲機關亦不得自行宣告該 法律案為無效", "法律案之立法程序有不待調查事實即可認定為牴觸憲法，亦即有違反法律成立基本規定之明顯 重大瑕疵者，釋憲機關仍得宣告其為無效", "法律案須由總統公布後始生效力，故核查法律案之立法程序是否存有瑕疵，進而須退回立法院 重新審議，應屬總統權限，與釋憲機關無涉"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "44394191c8ff", "answer_pdf_sha1": "345fcb11fcba", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗（作文、英文閱讀與法學知識）", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "文化行政"}'::jsonb, NULL)
